insert into public.questions (category_id, language_code, prompt, option_a, option_b, option_c, option_d, correct_option, explanation, difficulty, is_approved, question_type, image_url, source_url) values
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di destpêkê de, têgeha ''ergatîf'' a ku di qada ziman de derdikeve pêş, çi nîşan dide?', 'avahiya rêzimanî ya ku kirdeya lêkerên gerguhêz di dema borî de tewandî nîşan dide', 'cînavkên wekî ''min, te, wî, wê, me, we, wan'' ku di bin tewandinê de ne', 'hêmanên wekî ''-î, -ê, -an'' ku di tewandina navdêran de cih digirin', 'têkiliya artêla mê (a) û nêr (ê) ya ku navdêran bi hev ve girê dide', 'A', 'Tewandin, navdêr an cînavkan li gorî rola wan a hevokê (kirde/bireser/têkilî) diguherîne; mînak: ''kur'' dibe ''kurê''.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya ziman de wateya têgeha ''cînavkên tewandî'' bi awayekî herî rast nîşan dide?', 'têkiliya artêla mê (a) û nêr (ê) ya ku navdêran bi hev ve girê dide', 'hêmanên wekî ''-î, -ê, -an'' ku di tewandina navdêran de cih digirin', 'Ew wekî ''cînavkên wekî ''min, te, wî, wê, me, we, wan'' ku di bin tewandinê de ne'' tê pênasekirin.', 'nîşanderên wekî ''ez, tu, ew, em, hûn, ew'' ên ku bo kesan tên bikaranîn', 'C', 'Cînavkên tewandî (min, te, wî, wê, me, we, wan) kirde an bireserê hevokê di rewşên tewandî de temsîl dikin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya ziman de wateya têgeha ''daçekên hevedudanî'' bi awayekî herî rast nîşan dide?', 'Ew wekî ''peyvên wekî ''di... de, bi... re, ji... re'' ku têkiliyên cih nîşan didin'' tê pênasekirin.', 'cînavkên wekî ''min, te, wî, wê, me, we, wan'' ku di bin tewandinê de ne', 'hêmanên wekî ''-î, -ê, -an'' ku di tewandina navdêran de cih digirin', 'têkiliya artêla mê (a) û nêr (ê) ya ku navdêran bi hev ve girê dide', 'A', 'Daçekên hevedudanî ji du hêmanan pêk tên (mînak ''di...de'', ''bi...re'') û bi hev re têkiliyekê (cih, hevkarî, hwd.) diyar dikin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di destpêkê de, têgeha ''rênivîsa Hawarê'' a ku di qada ziman de derdikeve pêş, çi nîşan dide?', 'nîşanderên wekî ''ez, tu, ew, em, hûn, ew'' ên ku bo kesan tên bikaranîn', 'hêmanên wekî ''-î, -ê, -an'' ku di tewandina navdêran de cih digirin', 'peyvên wekî ''di... de, bi... re, ji... re'' ku têkiliyên cih nîşan didin', 'pergala alfabeya kurdî ya bi tîpên latînî ku ji aliyê Celadet Bedirxan ve hatibû amadekirin', 'D', 'Rênivîsa Hawarê pergala nivîsê ya bi tîpên latînî ye ku Celadet Alî Bedirxan ji bo Kurmancî amade kir; di kovara Hawarê de ji sala 1932an ve hat bikaranîn.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya ziman de wateya têgeha ''cînavkên kesane'' bi awayekî herî rast nîşan dide?', 'Ew wekî ''nîşanderên wekî ''ez, tu, ew, em, hûn, ew'' ên ku bo kesan tên bikaranîn'' tê pênasekirin.', 'avahiya lêkerê ya ku kiryarek di rabirdûyeke pir dûr de nîşan dide', 'avahiya rêzimanî ya ku kirdeya lêkerên gerguhêz di dema borî de tewandî nîşan dide', 'cînavkên wekî ''min, te, wî, wê, me, we, wan'' ku di bin tewandinê de ne', 'A', 'Cînavkên kesane (ez, tu, ew, em, hûn, ew) kesan temsîl dikin; ''ew'' hem yekhejmar hem pirhejmar bo kesê sêyem tê bikaranîn.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya ziman de wateya têgeha ''dema borî ya dûr'' bi awayekî herî rast nîşan dide?', 'Ew wekî ''avahiya lêkerê ya ku kiryarek di rabirdûyeke pir dûr de nîşan dide'' tê pênasekirin.', 'lêkerên ku hewcedariya wan bi artêla tewandî heye bo temamkirina wateyê', 'têkiliya artêla mê (a) û nêr (ê) ya ku navdêran bi hev ve girê dide', 'hêmanên wekî ''-î, -ê, -an'' ku di tewandina navdêran de cih digirin', 'A', 'Dema borî ya dûr bi paşgira ''-bû'' tê çêkirin û kiryareke ku beriya kiryareke din a di rabirdûyê de qediyaye nîşan dide.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya ziman de wateya têgeha ''paşgirên tewandinê'' bi awayekî herî rast nîşan dide?', 'avahiya lêkerê ya ku kiryarek di rabirdûyeke pir dûr de nîşan dide', 'peyvên wekî ''di... de, bi... re, ji... re'' ku têkiliyên cih nîşan didin', 'pergala alfabeya kurdî ya bi tîpên latînî ku ji aliyê Celadet Bedirxan ve hatibû amadekirin', 'Ew wekî ''hêmanên wekî ''-î, -ê, -an'' ku di tewandina navdêran de cih digirin'' tê pênasekirin.', 'D', 'Paşgirên tewandinê (-î, -ê, -an) li gorî zayend û hejmarê li dawiya navdêran tên zêdekirin da ku rola wan a rêzimanî nîşan bidin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di asta pêşketî de, di qada ziman de têgeha ''Ergatîf'' di heman demê de wekî ''avahiya rêzimanî ya ku kirdeya lêkerên gerguhêz di dema borî de tewandî nîşan dide'' tê binavkirin.', 'Rast', 'Şaş', '-', '-', 'A', 'Di dema borî ya lêkerên gerguhêz de kirde di rewşa tewandî de ye û bireser di rewşa binirte de dimîne; ev avahiya rêzimanî wekî ''ergatîf'' tê binavkirin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Ziman'), 'ku-kmr', 'Di asta pêşketî de, di qada ziman de têgeha ''Ezafe'' di heman demê de wekî ''têkiliya artêla mê (a) û nêr (ê) ya ku navdêran bi hev ve girê dide'' tê binavkirin.', 'Rast', 'Şaş', '-', '-', 'A', 'Ezafe, navdêrekê bi rengdêr an navdêrekê din ve girê dide û li gorî zayendê (mê: -a, nêr: -ê) diguhere; mînak ''kitêba min''.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya wêje de wateya têgeha ''Melayê Cizîrî'' bi awayekî herî rast nîşan dide?', 'romannivîsê kurd ê modern ku bi zimanekî kûr û edebî şoreşek di romana kurdî de çêkir', 'kovara edebî û çandî ya ku di sala 1932an de li Şamê bi destê Bedirxaniyan derketiye', 'Ew wekî ''helbestvanê mezin ê klasîk ku bi dîwana xwe ya felsefî û tesewifî tê naskirin'' tê pênasekirin.', 'helbestvanê ku Mewlûdaya Kurdî bi zaravayê kurmancî nivîsiye', 'C', 'Melayê Cizîrî (sedsala 16-17an) bi Dîwana xwe ya kurmancî ya kûr, felsefî û tesewifî tê naskirin û wekî yek ji stûnên şiîra klasîk a kurdî tê hesibandin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya wêje de wateya têgeha ''Feqiyê Teyran'' bi awayekî herî rast nîşan dide?', 'romannivîsê kurd ê modern ku bi zimanekî kûr û edebî şoreşek di romana kurdî de çêkir', 'rêbaza helbesta nûjen a bê pîvan û bê qafiye ku bi taybetî li ser peyvan ava dide', 'kovara edebî û çandî ya ku di sala 1932an de li Şamê bi destê Bedirxaniyan derketiye', 'Ew wekî ''helbestvanê klasîk ê ku bi berhema ''Şêx Sen''an'' û axaftina bi çûkan re navdar e'' tê pênasekirin.', 'D', 'Feqiyê Teyran bi berhemên xwe yên wekî ''Şêxê Sen''an'' û bi vegotinên xwe yên bi çûkan re tê naskirin; navê wî bi wateya ''zana yê çûkan'' ve tê şirovekirin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya wêje de wateya têgeha ''Ehmedê Xanî'' bi awayekî herî rast nîşan dide?', 'helbestvanê mezin ê klasîk ku bi dîwana xwe ya felsefî û tesewifî tê naskirin', 'Ew wekî ''nivîskarê destana nemir a ''Mem û Zîn'' ku hîmê ramanî yê kurdewariyê daniye'' tê pênasekirin.', 'rêbaza helbesta nûjen a bê pîvan û bê qafiye ku bi taybetî li ser peyvan ava dide', 'helbestvanê klasîk ê ku bi berhema ''Şêx Sen''an'' û axaftina bi çûkan re navdar e', 'B', 'Ehmedê Xanî di sala 1692an (an 1695) de destana ''Mem û Zîn'' nivîsî, ku wekî bingeha ramanî ya kurdewariyê tê dîtin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya wêje de wateya têgeha ''Melayê Bateyî'' bi awayekî herî rast nîşan dide?', 'kovara edebî û çandî ya ku di sala 1932an de li Şamê bi destê Bedirxaniyan derketiye', 'helbestvanê klasîk ê ku bi berhema ''Şêx Sen''an'' û axaftina bi çûkan re navdar e', 'civînên şevê yên ku tê de helbest û çîrokên klasîk û modern dihatin xwendin', 'Ew wekî ''helbestvanê ku Mewlûdaya Kurdî bi zaravayê kurmancî nivîsiye'' tê pênasekirin.', 'D', 'Melayê Bateyî Mewlûda Kurdî ya bi zaravayê kurmancî nivîsiye, ku hê jî di gelek meclîsên olî de tê xwendin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya wêje de wateya têgeha ''kovara Hawarê'' bi awayekî herî rast nîşan dide?', 'helbestvanê mezin ê klasîk ku bi dîwana xwe ya felsefî û tesewifî tê naskirin', 'Ew wekî ''kovara edebî û çandî ya ku di sala 1932an de li Şamê bi destê Bedirxaniyan derketiye'' tê pênasekirin.', 'helbestvanê şoreşger û civakî yê ku helbesta kurdî ya modern biriye qonaxeke nû', 'nivîskarê destana nemir a ''Mem û Zîn'' ku hîmê ramanî yê kurdewariyê daniye', 'B', 'Kovara Hawarê di sala 1932an de li Şamê ji aliyê malbata Bedirxan (bi taybetî Celadet Bedirxan) ve hat weşandin û di pêşxistina rênivîsa latînî ya kurdî de roleke sereke lîst.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya wêje de wateya têgeha ''Cegerxwîn'' bi awayekî herî rast nîşan dide?', 'Ew wekî ''helbestvanê şoreşger û civakî yê ku helbesta kurdî ya modern biriye qonaxeke nû'' tê pênasekirin.', 'nivîskarê kurd ê ku bi romana ''Şivanê Kurd'' di wêjeya modern de tê naskirin', 'nivîskarê destana nemir a ''Mem û Zîn'' ku hîmê ramanî yê kurdewariyê daniye', 'romannivîsê kurd ê modern ku bi zimanekî kûr û edebî şoreşek di romana kurdî de çêkir', 'A', 'Cegerxwîn bi helbestên xwe yên şoreşger û civakî (mînak berhevoka ''Diwan'') helbesta kurdî ya modern biriye qonaxeke nû.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya wêje de wateya têgeha ''Arabê Şamo'' bi awayekî herî rast nîşan dide?', 'Ew wekî ''nivîskarê kurd ê ku bi romana ''Şivanê Kurd'' di wêjeya modern de tê naskirin'' tê pênasekirin.', 'rêbaza helbesta nûjen a bê pîvan û bê qafiye ku bi taybetî li ser peyvan ava dide', 'romannivîsê kurd ê modern ku bi zimanekî kûr û edebî şoreşek di romana kurdî de çêkir', 'helbestvanê mezin ê klasîk ku bi dîwana xwe ya felsefî û tesewifî tê naskirin', 'A', 'Arabê Şemo (Arabê Şamo) bi romana xwe ya ''Şivanê Kurmanca'' (bi navê ''Şivanê Kurd'' jî tê zanîn) yek ji pêşengên roman a kurdî ya modern e.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, têgeha ''Mehmed Uzun'' a ku di qada wêje de derdikeve pêş, çi nîşan dide?', 'helbestvanê ku Mewlûdaya Kurdî bi zaravayê kurmancî nivîsiye', 'romannivîsê kurd ê modern ku bi zimanekî kûr û edebî şoreşek di romana kurdî de çêkir', 'helbestvanê mezin ê klasîk ku bi dîwana xwe ya felsefî û tesewifî tê naskirin', 'helbestvanê şoreşger û civakî yê ku helbesta kurdî ya modern biriye qonaxeke nû', 'B', 'Mehmed Uzun bi romanên xwe yên bi zimanekî kûr û edebî (mînak ''Mirina Kalekî Rind'') şoreşek di romana kurdî ya modern de çêkir.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Edebiyat'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya wêje de wateya têgeha ''Helbesta Azad'' bi awayekî herî rast nîşan dide?', 'Ew wekî ''rêbaza helbesta nûjen a bê pîvan û bê qafiye ku bi taybetî li ser peyvan ava dide'' tê pênasekirin.', 'nivîskarê destana nemir a ''Mem û Zîn'' ku hîmê ramanî yê kurdewariyê daniye', 'romannivîsê kurd ê modern ku bi zimanekî kûr û edebî şoreşek di romana kurdî de çêkir', 'helbestvanê klasîk ê ku bi berhema ''Şêx Sen''an'' û axaftina bi çûkan re navdar e', 'A', 'Helbesta azad rêbazeke helbestî ye ku bê pîvana kevneşopî (arûz/hece) û bê qafiyeya sabît tê nivîsandin, li ser hêza peyvê ava dibe.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya dîrok de wateya têgeha ''Împaratoriya Medî'' bi awayekî herî rast nîşan dide?', 'rojnameya yekem a kurdî ku di sala 1898an de li Qahîreyê ji aliyê Mîqdat Mîdhad Bedirxan ve hat weşandin', 'weşana dîrokî ya kurdî ya serdema destpêka sedsala 20an ku li ser mafên neteweyî dinivîsî', 'Ew wekî ''hêza antîk a li herêma Zagrosê ku di dîroka kevn a herêmê de cih digire'' tê pênasekirin.', 'mîrnişîna kurdî ya bihêz a ku navenda wê Cizîra Botan bû û xwedî serxwebûneke çandî bû', 'C', 'Împaratoriya Medî (sedsala 7-6an B.Z.) li herêma Zagrosê hêzek antîk bû; girêdana rasterast a etnîkî ya di navbera Medan û kurdên îroyîn de di nav lêkolîneran de mijareke nîqaşê ye, lê wekî ''hêzek antîk a herêmê'' gotin rast e.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya dîrok de wateya têgeha ''Dewleta Merwaniyan'' bi awayekî herî rast nîşan dide?', 'mîrnişîna kurdî ya bihêz a ku navenda wê Cizîra Botan bû û xwedî serxwebûneke çandî bû', 'weşana dîrokî ya kurdî ya serdema destpêka sedsala 20an ku li ser mafên neteweyî dinivîsî', 'serokê mezin ê kurd ku Quds ji xaçperestan rizgar kir û xanedaniya Eyûbiyan ava kir', 'Ew wekî ''xanedaniya kurdî ya serdema navîn ku navenda wê Amed û doralên wê bûn'' tê pênasekirin.', 'D', 'Dewleta Merwaniyan (990-1085) xanedaneke kurdî ya serdema navîn bû, navenda wê Amed (Diyarbekir) bû.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, têgeha ''Mîrgeha Botan'' a ku di qada dîrok de derdikeve pêş, çi nîşan dide?', 'mîrê navdar ê Soran ku di sedsala 19an de hewl da yekîtiya kurdî ava bike', 'mîrnişîna kurdî ya bihêz a ku navenda wê Cizîra Botan bû û xwedî serxwebûneke çandî bû', 'rojnameya yekem a kurdî ku di sala 1898an de li Qahîreyê ji aliyê Mîqdat Mîdhad Bedirxan ve hat weşandin', 'mîrnişîneke kevnar a kurdî ya li rojhilat ku navenda wê Sine bû', 'B', 'Mîrgeha Botan bi navenda xwe ya Cizîra Botan mîrnişîneke kurdî ya bihêz û xwedî serxwebûneke çandî ya berbiçav bû.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, têgeha ''Şerefname'' a ku di qada dîrok de derdikeve pêş, çi nîşan dide?', 'serokê mezin ê kurd ku Quds ji xaçperestan rizgar kir û xanedaniya Eyûbiyan ava kir', 'mîrê navdar ê Soran ku di sedsala 19an de hewl da yekîtiya kurdî ava bike', 'rojnameya yekem a kurdî ku di sala 1898an de li Qahîreyê ji aliyê Mîqdat Mîdhad Bedirxan ve hat weşandin', 'pirtûka dîroka mîrgehên kurdî ku di sala 1597an de ji aliyê Şerefxanê Bedlîsî ve hatibû nivîsandin', 'D', 'Şerefname di sala 1597an de ji aliyê Şerefxanê Bedlîsî ve hat nivîsandin û dîroka mîrgehên kurdî vedibêje; wekî çavkaniyeke destpêkî ya sereke ya dîroka kurdî tê dîtin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, têgeha ''Kovara Jîn'' a ku di qada dîrok de derdikeve pêş, çi nîşan dide?', 'peymana navdewletî ya sala 1923an ku piştî Şerê Cîhanê Yê Yekem çarçoveya hin sînorên herêmê ava kir', 'weşana dîrokî ya kurdî ya serdema destpêka sedsala 20an ku li ser mafên neteweyî dinivîsî', 'mîrnişîna kurdî ya bihêz a ku navenda wê Cizîra Botan bû û xwedî serxwebûneke çandî bû', 'hêza antîk a li herêma Zagrosê ku di dîroka kevn a herêmê de cih digire', 'B', 'Kovara Jîn di navbera 1918-1919an de li Stenbolê hat weşandin û li ser mafên neteweyî yên kurdan dinivîsî.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, têgeha ''Selaheddînê Eyûbî'' a ku di qada dîrok de derdikeve pêş, çi nîşan dide?', 'serokê mezin ê kurd ku Quds ji xaçperestan rizgar kir û xanedaniya Eyûbiyan ava kir', 'weşana dîrokî ya kurdî ya serdema destpêka sedsala 20an ku li ser mafên neteweyî dinivîsî', 'xanedaniya kurdî ya serdema navîn ku navenda wê Amed û doralên wê bûn', 'mîrnişîna kurdî ya bihêz a ku navenda wê Cizîra Botan bû û xwedî serxwebûneke çandî bû', 'A', 'Selaheddînê Eyûbî di sala 1187an de Quds ji Xaçperestan rizgar kir û xanedaniya Eyûbiyan ava kir; koka wî ya kurdî di nav dîroknasan de bi berfirehî tê qebûlkirin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, têgeha ''Rojnameya Kurdistan'' a ku di qada dîrok de derdikeve pêş, çi nîşan dide?', 'pirtûka dîroka mîrgehên kurdî ku di sala 1597an de ji aliyê Şerefxanê Bedlîsî ve hatibû nivîsandin', 'serokê mezin ê kurd ku Quds ji xaçperestan rizgar kir û xanedaniya Eyûbiyan ava kir', 'rojnameya yekem a kurdî ku di sala 1898an de li Qahîreyê ji aliyê Mîqdat Mîdhad Bedirxan ve hat weşandin', 'mîrnişîneke kevnar a kurdî ya li rojhilat ku navenda wê Sine bû', 'C', 'Rojnameya Kurdistan di sala 1898an de li Qahîreyê ji aliyê Mîqdad Mîdhad Bedirxan ve hat weşandin û wekî rojnameya kurdî ya yekem tê pejirandin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, kîjan vebijark di çarçoveya dîrok de wateya têgeha ''Mîrgeha Erdelanê'' bi awayekî herî rast nîşan dide?', 'serokê mezin ê kurd ku Quds ji xaçperestan rizgar kir û xanedaniya Eyûbiyan ava kir', 'peymana navdewletî ya sala 1923an ku piştî Şerê Cîhanê Yê Yekem çarçoveya hin sînorên herêmê ava kir', 'Ew wekî ''mîrnişîneke kevnar a kurdî ya li rojhilat ku navenda wê Sine bû'' tê pênasekirin.', 'mîrnişîna kurdî ya bihêz a ku navenda wê Cizîra Botan bû û xwedî serxwebûneke çandî bû', 'C', 'Mîrgeha Erdelanê mîrnişîneke kevnar a kurdî bû, navenda wê Sine (Sanandeç) bû.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Dîrok'), 'ku-kmr', 'Di destpêkê de, têgeha ''Peymana Lozanê'' a ku di qada dîrok de derdikeve pêş, çi nîşan dide?', 'peymana navdewletî ya sala 1923an ku piştî Şerê Cîhanê Yê Yekem çarçoveya hin sînorên herêmê ava kir', 'mîrê navdar ê Soran ku di sedsala 19an de hewl da yekîtiya kurdî ava bike', 'mîrnişîneke kevnar a kurdî ya li rojhilat ku navenda wê Sine bû', 'serokê mezin ê kurd ku Quds ji xaçperestan rizgar kir û xanedaniya Eyûbiyan ava kir', 'A', 'Peymana Lozanê di sala 1923an de piştî Şerê Cîhanê yê Yekem hat îmzekirin û çarçoveya sînorên hin dewletên herêmê (di nav wan de tunebûna dewleteke kurdî ya serbixwe) diyar kir.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
((select id from public.categories where name = 'Cografya'), 'ku-kmr', 'Di destpêkê de, têgeha ''çiyayên Zagrosê'' a ku di qada erdnîgarî de derdikeve pêş, çi nîşan dide?', 'yek ji du çemên herî mezin ên Mezopotamyayê ku jiyanê dide axên berdar', 'bajarê kevnar û dîrokî yê li ser çemê Dîcleyê ku xwedî şikeftên bêhempa ye', 'rêzeçiyayên mezin û asê yên ku sînorê xwezayî yê welatê kurdan pêk tînin', 'şûna arkeolojîk a li nêzîkî bajarê Rihayê ku ji bo lêkolîna dîroka destpêkê girîng e', 'C', 'Çiyayên Zagrosê rêzeçiyayên mezin in ku di edebiyata çandî/erdnîgarî de wekî sînorê xwezayî yê deverên bi zorbeyî kurdî dijîn tê binavkirin.', 2, false, 'multiple_choice', NULL, 'editorial_ai_review_pending'),
